// Extract event data from Terra-OS webhook
const body = $input.first().json.body;
const event = body.event;
const entity = body.entity_data;

if (event !== 'kosztorys.send_pdf' && event !== 'kosztorys.ready') {
  return []; // skip non-PDF events
}

return [{
  json: {
    kosztorys_id: body.entity_id,
    nazwa: entity.nazwa || 'Kosztorys',
    inwestor: entity.inwestor || '',
    suma_netto: entity.suma_netto || 0,
    triggered_by: body.triggered_by,
    event: event,
  }
}];
